def encrypt(s):
    encrypted = []
    for char in s:
        if char.isalpha():
            shift = 2 * 2  # Two multiplied to two places
            alphabet = 'abcdefghijklmnopqrstuvwxyz' if char.islower() else 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'
            new_index = (alphabet.index(char) + shift) % len(alphabet)
            encrypted.append(alphabet[new_index])
        else:
            encrypted.append(char)
    return ''.join(encrypted)

def encrypt(s):
    encrypted = []
    for char in s:
        if 'a' <= char <= 'z':
            offset = (2 * 2) % 26
            shifted = chr((ord(char) - ord('a') + offset) % 26 + ord('a'))
            encrypted.append(shifted)
        elif 'A' <= char <= 'Z':
            offset = (2 * 2) % 26
            shifted = chr((ord(char) - ord('A') + offset) % 26 + ord('A'))
            encrypted.append(shifted)
        else:
            encrypted.append(char)
    return ''.join(encrypted)

