def fix_spaces(text):
    result = []
    space_count = 0

    for char in text:
        if char == ' ':
            space_count += 1
            continue

        if space_count > 2:
            result.append('-')
        elif space_count >= 1:
            result.extend(['_'] * space_count)

        result.append(char)
        space_count = 0

    if space_count > 2:
        result.append('-')
    elif space_count >= 1:
        result.extend(['_'] * space_count)

    return ''.join(result)

from typing import List


def separate_paren_groups(paren_string: str) -> List[str]:
    result = []
    stack = []
    current_group = []

    for char in paren_string.replace(' ', ''):
        if char == '(':
            stack.append(char)
            current_group.append(char)
        elif char == ')':
            stack.pop()
            current_group.append(char)
            if not stack:
                result.append(''.join(current_group))
                current_group = []

    return result

