def minPath(grid, k):
    N = len(grid)

    # Initialize the distance matrix with infinity (except start positions)
    distances = [[float('inf')] * N for _ in range(N)]
    for i in range(N):
        for j in range(N):
            if grid[i][j] == 1:
                distances[i][j] = 0

    # Define possible directions for movement
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    # BFS to find the minimum path of length k
    from collections import deque
    queue = deque([(i, j, 1) for i in range(N) for j in range(N)])
    while queue:
        x, y, steps = queue.popleft()
        if steps == k:
            break
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N:
                new_steps = steps + 1
                if distances[nx][ny] > new_steps:
                    distances[nx][ny] = new_steps
                    queue.append((nx, ny, new_steps))

    # Reconstruct the path from the distance matrix
    path = []
    for i in range(N):
        for j in range(N):
            if distances[i][j] == k-1:
                path.append(grid[i][j])
                break
        else:
            continue
        break

    return path

