def minPath(grid, k):
    N = len(grid)
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    dist = [[float('inf')] * N for _ in range(N)]
    pq = []

    start_cells = [(i, j) for i in range(N) for j in range(N)]
    for x, y in start_cells:
        dist[x][y] = grid[x][y]
        heappush(pq, (grid[x][y], x, y))

    while pq:
        min_val, x, y = heappop(pq)
        if len(min_path) == k:
            return []

