def get_odd_collatz(n):
    def collatz_sequence(num):
        while num != 1:
            yield num
            if num % 2 == 0:
                num //= 2
            else:
                num = 3 * num + 1
        yield 1  # The sequence always reaches 1

    odd_numbers = list(filter(lambda x: x % 2 != 0, collatz_sequence(n)))
    return sorted(odd_numbers)

