def anti_shuffle(s):
    words = s.split()
    ordered_words = [''.join(sorted(word)) for word in words]
    return ' '.join(ordered_words)

def correct_bracketing(brackets: str) -> bool:
    balance = 0
    for bracket in brackets:
        if bracket == '(':
            balance += 1
        elif bracket == ')':
            balance -= 1
        if balance < 0:
            return False
    return balance == 0

