def find_max(words):
    def unique_char_count(word):
        return len(set(word)), word

    max_unique_word = ""
    max_unique_count = 0

    for word in words:
        count, word = unique_char_count(word)
        if count > max_unique_count or (count == max_unique_count and word < max_unique_word):
            max_unique_count = count
            max_unique_word = word

    return max_unique_word

